class MedianFinder {
  constructor() {
    this.small = []; // Max-heap
    this.large = []; // Min-heap
  }

  addNum(num) {
    this.insert(this.small, num, (a, b) => b - a);
    this.insert(this.large, this.small.shift(), (a, b) => a - b);

    if (this.large.length > this.small.length) {
      this.insert(this.small, this.large.shift(), (a, b) => b - a);
    }
  }

  insert(arr, val, compare) {
    let low = 0, high = arr.length;
    while (low < high) {
      let mid = (low + high) >>> 1;
      if (compare(arr[mid], val) < 0) low = mid + 1;
      else high = mid;
    }
    arr.splice(low, 0, val);
  }

  findMedian() {
    if (this.small.length > this.large.length) {
      return this.small[0];
    }
    return (this.small[0] + this.large[0]) / 2;
  }
}

function medianFinderHandler(ops, params) {
  let mf = null;
  return ops.map((op, i) => {
    if (op === 'MedianFinder') {
      mf = new MedianFinder();
      return null;
    }
    return mf[op](...params[i]);
  });
}
